insert into public.programs (name, description, duration_weeks, days_per_week, goal_tag, difficulty, is_active, structure)
select 'Push / Pull / Legs', 'A 6-day PPL program that trains every muscle twice per week. Two distinct Push, Pull, and Leg sessions hit different angles and rep ranges across 6 weeks — Accumulation (weeks 1–3) builds volume, Intensification (weeks 4–6) drives strength. Ideal for intermediate lifters ready to go beyond 4 days.', 6, 6, 'bulk', 'intermediate', true, '{"weeks":[{"label":"Week 1","rep_note":"<b>Accumulation Phase.</b> Main lifts: <b>8–12 reps</b>. Accessories: <b>10–12 reps</b>. Add weight when you hit the top of every set.","days":[{"title":"Push A — Chest · Shoulders · Triceps","sub":"Day 1 — Push A","groups":[{"name":"CHEST","exercises":[{"name":"Barbell Bench Press","sets":4,"reps":"8–12","note":"Feet flat. Bar to lower chest. Elbows at 45°.","swap_category":"chest_multi"},{"name":"Incline DB Press","sets":3,"reps":"10–12","note":"30° incline. Full press. Squeeze at top.","swap_category":"chest_multi"},{"name":"Cable Crossover","sets":3,"reps":"10–12","note":"Low pulleys. Cross hands at bottom. Slow negative.","swap_category":"chest_single"}]},{"name":"SHOULDERS","exercises":[{"name":"DB Lateral Raise","sets":3,"reps":"10–12","note":"Slight lean forward. Thumbs slightly down.","swap_category":"shoulders"}]},{"name":"TRICEPS","exercises":[{"name":"Cable Pushdown (Rope)","sets":3,"reps":"10–12","note":"Spread rope at bottom. Elbows pinned.","swap_category":"triceps"},{"name":"Overhead Tricep Extension (DB)","sets":3,"reps":"10–12","note":"Both hands on one DB. Full stretch overhead.","swap_category":"triceps"}]}]},{"title":"Pull A — Back · Biceps · Rear Delt","sub":"Day 2 — Pull A","groups":[{"name":"BACK","exercises":[{"name":"Barbell Row (Overhand)","sets":4,"reps":"8–12","note":"Hinge 45°. Pull to lower chest. Elbows back.","swap_category":"back_multi"},{"name":"Pull-Up / Lat Pulldown","sets":3,"reps":"10–12","note":"Full hang. Lead elbows down and back.","swap_category":"back_multi"},{"name":"Seated Cable Row","sets":3,"reps":"10–12","note":"Chest up. Full contraction, slow release.","swap_category":"back_single"}]},{"name":"REAR DELT","exercises":[{"name":"Cable Face Pull","sets":3,"reps":"10–12","note":"Rope to forehead. Elbows high and wide.","swap_category":"shoulders"}]},{"name":"BICEPS","exercises":[{"name":"Barbell Curl","sets":3,"reps":"8–12","note":"No swinging. Full extension at bottom.","swap_category":"biceps"},{"name":"Incline DB Curl","sets":3,"reps":"10–12","note":"Elbows behind body for maximum stretch.","swap_category":"biceps"}]}]},{"title":"Legs A — Quads · Hamstrings · Calves","sub":"Day 3 — Legs A","groups":[{"name":"QUADS","exercises":[{"name":"Barbell Back Squat","sets":4,"reps":"8–12","note":"Depth below parallel. Drive knees out.","swap_category":"legs_multi"},{"name":"Leg Press","sets":3,"reps":"10–12","note":"Feet shoulder-width. Full ROM. No lockout.","swap_category":"legs_multi"},{"name":"Leg Extension","sets":3,"reps":"10–12","note":"Pause at top. 3-sec negative.","swap_category":"legs_single"}]},{"name":"HAMSTRINGS","exercises":[{"name":"Romanian Deadlift","sets":3,"reps":"8–12","note":"Hip hinge. Feel the hamstring stretch.","swap_category":"legs_multi"},{"name":"Lying Leg Curl","sets":3,"reps":"10–12","note":"Full ROM. Controlled negative.","swap_category":"legs_single"}]},{"name":"CALVES","exercises":[{"name":"Standing Calf Raise","sets":4,"reps":"12–20","note":"Full stretch at bottom. Pause at top.","swap_category":"calves"}]}]},{"title":"Push B — Shoulders · Chest · Triceps","sub":"Day 4 — Push B","groups":[{"name":"SHOULDERS","exercises":[{"name":"Barbell Overhead Press","sets":4,"reps":"8–12","note":"Standing. Brace core. Full lockout overhead.","swap_category":"shoulders"},{"name":"DB Lateral Raise","sets":3,"reps":"10–12","note":"Controlled. No momentum. Thumbs down.","swap_category":"shoulders"},{"name":"Cable Face Pull","sets":3,"reps":"10–12","note":"Rope to forehead. External rotation focus.","swap_category":"shoulders"}]},{"name":"CHEST","exercises":[{"name":"Incline Barbell Press","sets":3,"reps":"10–12","note":"30° incline. Control down, explode up.","swap_category":"chest_multi"},{"name":"Pec Deck Fly","sets":3,"reps":"10–12","note":"Lead with elbows. Slow 3-sec negative.","swap_category":"chest_single"}]},{"name":"TRICEPS","exercises":[{"name":"Close-Grip Bench Press","sets":3,"reps":"8–12","note":"Hands shoulder-width. Elbows tucked.","swap_category":"triceps"},{"name":"Cable Pushdown (Bar)","sets":3,"reps":"10–12","note":"Elbows pinned at sides. Full extension.","swap_category":"triceps"}]}]},{"title":"Pull B — Lats · Traps · Biceps","sub":"Day 5 — Pull B","groups":[{"name":"BACK","exercises":[{"name":"Weighted Pull-Up","sets":4,"reps":"8–12","note":"Full hang to chin over bar. Slow descent.","swap_category":"back_multi"},{"name":"Pendlay Row","sets":3,"reps":"10–12","note":"Dead stop each rep. Explode up. Control down.","swap_category":"back_multi"},{"name":"Wide-Grip Lat Pulldown","sets":3,"reps":"10–12","note":"Pull to upper chest. Elbows down and back.","swap_category":"back_single"}]},{"name":"TRAPS","exercises":[{"name":"Barbell Shrug","sets":3,"reps":"10–12","note":"Straight up. Hold 1 sec. No rolling.","swap_category":"traps"}]},{"name":"BICEPS","exercises":[{"name":"EZ-Bar Curl","sets":3,"reps":"8–12","note":"Full extension at bottom. No swinging.","swap_category":"biceps"},{"name":"DB Hammer Curl","sets":3,"reps":"10–12","note":"Neutral grip. Alternate arms.","swap_category":"biceps"}]}]},{"title":"Legs B — Hamstrings · Glutes · Quads","sub":"Day 6 — Legs B","groups":[{"name":"HAMSTRINGS","exercises":[{"name":"Conventional Deadlift","sets":4,"reps":"8–12","note":"Brace hard. Drive the floor away. Lock hips out.","swap_category":"back_multi"},{"name":"Bulgarian Split Squat","sets":3,"reps":"10–12","note":"Torso upright. Front heel drive. Full depth.","swap_category":"legs_single"},{"name":"Nordic Curl","sets":3,"reps":"4–6","note":"Slow eccentric. Use band for assistance if needed.","swap_category":"legs_singl