select 'Upper / Lower Classic', 'An 8-week bodybuilder-style upper/lower split. Four days a week: two upper sessions and two lower sessions, each pairing a heavy strength day with a volume day. Rep ranges wave downward across 8 weeks — from hypertrophy work (10–12) all the way to near-max strength (4–6).', 8, 4, 'bulk', 'intermediate', true, '{"weeks":[{"label":"Week 1","rep_note":"<b>Hypertrophy Block.</b> Main lifts: <b>10–12 reps</b>. Accessories: <b>12–15 reps</b>. Focus on the squeeze, not the weight.","days":[{"title":"Upper Body — Heavy","sub":"Day 1 — Upper Heavy","groups":[{"name":"CHEST","exercises":[{"name":"Barbell Bench Press","sets":4,"reps":"10–12","note":"Arch slightly. Bar to lower chest. Full ROM.","swap_category":"chest_multi"},{"name":"Incline DB Press","sets":3,"reps":"12–15","note":"30° incline. Squeeze at top. Slow negative.","swap_category":"chest_multi"}]},{"name":"BACK","exercises":[{"name":"Barbell Row (Overhand)","sets":4,"reps":"10–12","note":"Hinge 45°. Pull to lower chest. Control down.","swap_category":"back_multi"},{"name":"Weighted Pull-Up","sets":3,"reps":"10–12","note":"Full hang. Chin over bar. Slow descent.","swap_category":"back_multi"}]},{"name":"SHOULDERS","exercises":[{"name":"Barbell Overhead Press","sets":3,"reps":"10–12","note":"Standing. Core tight. Full lockout.","swap_category":"shoulders"}]},{"name":"ARMS","exercises":[{"name":"EZ-Bar Curl","sets":3,"reps":"12–15","note":"No swinging. Full extension at bottom.","swap_category":"biceps"},{"name":"Close-Grip Bench Press","sets":3,"reps":"12–15","note":"Elbows tucked. Tricep focus.","swap_category":"triceps"}]}]},{"title":"Lower Body — Heavy","sub":"Day 2 — Lower Heavy","groups":[{"name":"QUADS","exercises":[{"name":"Barbell Back Squat","sets":4,"reps":"10–12","note":"Depth below parallel. Drive knees out.","swap_category":"legs_multi"},{"name":"Bulgarian Split Squat","sets":3,"reps":"12–15","note":"Torso upright. Front heel drive.","swap_category":"legs_single"}]},{"nam