select 'Rotating Split', 'A continuous 5-day rotation (Push · Pull · Legs · Upper · Full Body) designed to run indefinitely. Train 6 days, rest 1 — but the rotation doesn''t reset on a calendar week, so rest happens naturally. Complete the 6-week block and repeat. Small weight bumps at weeks 3 and 5.', 6, 6, 'maintain', 'beginner', true, '{"weeks":[{"label":"Week 1","rep_note":"<b>10–12 reps</b> on all exercises. First week — get familiar with the rotation. Move well, not heavy.","days":[{"title":"Push — Chest · Shoulders · Triceps","sub":"Day 1 — Push","groups":[{"name":"CHEST","exercises":[{"name":"Barbell Bench Press","sets":3,"reps":"10–12","note":"Controlled descent. Drive through bar.","swap_category":"chest_multi"},{"name":"Incline DB Press","sets":3,"reps":"10–12","note":"Full press. Squeeze at top.","swap_category":"chest_multi"},{"name":"Pec Deck Fly","sets":3,"reps":"10–12","note":"Slow negative. Lead with elbows.","swap_category":"chest_single"}]},{"name":"SHOULDERS","exercises":[{"name":"DB Shoulder Press","sets":3,"reps":"10–12","note":"Seated or standing. Full lockout.","swap_category":"shoulders"},{"name":"DB Lateral Raise","sets":3,"reps":"10–12","note":"Controlled. Slight forward lean.","swap_category":"shoulders"}]},{"name":"TRICEPS","exercises":[{"name":"Cable Pushdown (Rope)","sets":3,"reps":"10–12","note":"Spread rope. Elbows pinned.","swap_category":"triceps"}]}]},{"title":"Pull — Back · Biceps · Rear Delt","sub":"Day 2 — Pull","groups":[{"name":"BACK","exercises":[{"name":"Pull-Up / Lat Pulldown","sets":3,"reps":"10–12","note":"Full hang. Lead elbows down and back.","swap_category":"back_multi"},{"name":"Barbell Row","sets":3,"reps":"10–12","note":"Hinge 45°. Bar to lower chest.","swap_category":"back_multi"},{"name":"Seated Cable Row","sets":3,"reps":"10–12","note":"Chest up. Full contraction.","swap_category":"back_single"}]},{"name":"REAR DELT","exercises":[{"name":"Cable Face Pull","sets":3,"reps":"10–12","note":"Rope to forehead. Elbows 